/// <summary>
/// Extension for InventJournalTrans datasource on InventJournalMovement form.
/// Controls create/delete permissions and Qty field editability
/// based on ETGProductionConsumption flag from Journal Name.
/// </summary>
[ExtensionOf(formDataSourceStr(InventJournalMovement, InventJournalTrans))]
final class ETGInventJournalMovement_InventTrans_Extension
{
}

Method.Source:
public int active()
{
    InventJournalTrans inventJournalTrans=this.cursor();
    InventJournalTable inventJournalTable=this.formRun().dataSource(formDataSourceStr(InventJournalMovement,InventJournalTable)).cursor();
    InventJournalName inventJournalName=inventJournalTable.inventJournalName();
    int ret=next active();

    if(inventJournalName.ETGProductionConsumption==NoYes::Yes)
    {
        this.allowDelete(false);
        this.allowCreate(false);
        this.object(fieldNum(InventJournalTrans,Qty)).allowEdit(false);
    }
    else
    {
        this.allowDelete(true);
        this.allowCreate(true);
        this.object(fieldNum(InventJournalTrans,Qty)).allowEdit(true);
    }

    //CS - BIN Qty Status activation - Abhinav
    FormPartControl formpartcontrol = this.formRun().design().controlName("ETGBinQtyAvailable");
    formpartcontrol.visible(ETGCanadaParameters::find().EnableBinQtyStatus);

    if(ETGCanadaParameters::find().EnableBinQtyStatus)
    {
        InventDim inventdim = InventJournalTrans.inventDim();
        ETGBinQtyVisualChartHelperClass::populateBinQtyChartData(inventdim,formpartcontrol);
    }
    //CE

    return ret;

}

public void selectionChanged()
{
    InventJournalTrans inventJournalTrans=this.cursor();
    InventJournalTable inventJournalTable=this.formRun().dataSource(formDataSourceStr(InventJournalMovement,InventJournalTable)).cursor();
    InventJournalName inventJournalName=inventJournalTable.inventJournalName();
    next selectionChanged();


     if(inventJournalName.ETGProductionConsumption==NoYes::Yes)

    {
        this.allowDelete(false);
        this.allowCreate(false);
        this.object(fieldNum(InventJournalTrans,Qty)).allowEdit(false);
    }
    else
    {
        this.allowDelete(true);
        this.allowCreate(true);
        this.object(fieldNum(InventJournalTrans,Qty)).allowEdit(true);
    }
}
